def find_hamiltonian_path(graph):
    num_nodes = len(graph)
    if num_nodes == 0:
        return None
    if num_nodes == 1:
        return list(graph.keys())

    def _hamiltonian_path_util(current_vertex, path, visited):
        if len(path) == num_nodes:
            return path

        for neighbor in graph.get(current_vertex, []):
            if neighbor not in visited:
                path.append(neighbor)
                visited.add(neighbor)

                result = _hamiltonian_path_util(neighbor, path, visited)
                if result:
                    return result

                visited.remove(neighbor)
                path.pop()

        return None

    for start_vertex in graph.keys():
        path = [start_vertex]
        visited = {start_vertex}
        solution = _hamiltonian_path_util(start_vertex, path, visited)
        if solution:
            return solution

    return None
